<?php
require_once __DIR__.'/app/classes/Session.php'; require_once __DIR__.'/app/classes/Message.php'; require_once __DIR__.'/app/classes/GestionFichier.php';
Session::requireLogin(); $u=Session::user(); header('Content-Type: application/json');
try{ $contenu=trim($_POST['contenu'] ?? ''); $type=$_POST['type'] ?? 'public'; $coursId=(int)($_POST['cours_id'] ?? 1); $receiverId=(int)($_POST['receiver_id'] ?? 0); $fichier=null; if(!empty($_FILES['fichier']['tmp_name'])) $fichier=(new GestionFichier())->sauvegarder($_FILES['fichier']); if($contenu==='' && !$fichier) throw new RuntimeException('Message vide.'); $msg=match($type){ 'prive'=>new MessagePrive($u['id'],$contenu,$receiverId,null,$fichier), 'mur_pedagogique'=>new MurPedagogique($u['id'],$contenu,null,$coursId,$fichier), default=>new MessagePublic($u['id'],$contenu,null,$coursId,$fichier)}; $id=$msg->envoyer(); echo json_encode(['ok'=>true,'id'=>$id,'fichier'=>$fichier]); } catch(Throwable $e){ http_response_code(400); echo json_encode(['ok'=>false,'message'=>$e->getMessage()]); }
